parameters.jsCode:
/**
 * PROMPT BUILDER (v10)
 * Cross-session continuity, task follow-up, phase-goal steering,
 * anti-repetition, distress support, and structured-plan mode.
 */

const webhookNode = $("Webhook").first();
if (!webhookNode) throw new Error("Webhook node not found.");

const data = webhookNode.json.body || webhookNode.json || {};

const pd = data.profile || {};
const memories = data.memories || [];
const activeTasks = data.recent_tasks_assigned || [];
const messages = data.messages || [];

// Server-authoritative continuity pack (from edge function)
const last20 = Array.isArray(data.last_20_conversations) ? data.last_20_conversations : [];
const activeTasksCtx = Array.isArray(data.active_tasks_context) ? data.active_tasks_context : [];
const caseNotesCtx = Array.isArray(data.recent_case_notes_context) ? data.recent_case_notes_context : [];
const phaseCtx = data.continuity_phase_context || null;
const serverSessionStage = data.session_stage || "early";

const coachPrompt = data.coach_prompt || "You are an empathetic, non-judgmental mental health coach.";
const phasePrompt = data.phase_prompt || "Focus on building therapeutic rapport.";
const theme = data.dynamic_theme || "Not yet identified";
const messageCount = data.message_count || 1;
const profileId = data.profile_id || "";
const sessionId = data.session_id || "";
const isGreeting = data.is_system_greeting === true;
const latestUserMessage = String(data.message_text || "").trim();
const sessionNumber = data.session_number || 1;

const personalDetails = [
  "Name: " + (pd.name || "Unknown"),
  "Age: " + (pd.age || "Unknown"),
  "Gender: " + (pd.gender || "Unknown"),
  "Concerns: " + (Array.isArray(pd.concerns) ? pd.concerns.join(", ") : pd.concerns || "Not specified"),
].join("\n");

const mem0 = memories[0];
const memoriesStr = mem0
  ? String(mem0.memory_text || mem0.text || "")
  : "  None recorded.";

// Cross-session transcript (last 20 turns from recent sessions)
const crossSessionTurns = last20.length > 0 ? last20 : messages.slice(-20);
const transcript = crossSessionTurns
  .map(
    (m) =>
      "  " + (m.role === "user" ? "Client" : "Therapist") + ": " + String(m.content || "")
  )
  .join("\n");

// Current-session-only transcript for anti-repetition analysis
const currentSessionMessages = messages.slice(-15);

const userTurns = messages.filter((m) => m.role === "user").slice(-8).map((m) => String(m.content || ""));
const previousUserMessage = userTurns.length >= 2 ? userTurns[userTurns.length - 2] : "";
const recentTherapistTurns = messages
  .filter((m) => m.role === "assistant")
  .slice(-4)
  .map((m) => String(m.content || "").toLowerCase());

const lowerLatest = latestUserMessage.toLowerCase();
const lowerPrevious = String(previousUserMessage || "").toLowerCase();

const asksForStructuredPlan = /\b(plan|structured plan|step by step|steps|roadmap|action plan|what should i do)\b/i.test(latestUserMessage);

const elevatedDistressSignals = [
  "worthless", "empty", "broken", "hopeless",
  "i feel alone", "i am alone", "numb", "shutting down",
  "i can't do this", "i am failing",
];
const crisisSignals = [
  "kill myself", "end my life", "suicide",
  "self harm", "hurt myself", "want to die",
];

const elevatedDistressDetected = elevatedDistressSignals.some((s) => lowerLatest.includes(s));
const explicitCrisisCue = crisisSignals.some((s) => lowerLatest.includes(s));

const repeatedConcern =
  lowerLatest.length > 0 &&
  lowerPrevious.length > 0 &&
  (lowerLatest === lowerPrevious ||
    (lowerLatest.length > 24 && lowerPrevious.includes(lowerLatest.slice(0, 24))) ||
    (lowerPrevious.length > 24 && lowerLatest.includes(lowerPrevious.slice(0, 24))));

const repetitiveTherapistPatterns = [
  "that makes sense", "it sounds like", "thank you for sharing",
  "can you tell me more", "how does that make you feel",
];
const repeatedTherapistOpeners = repetitiveTherapistPatterns.filter((p) =>
  recentTherapistTurns.some((turn) => turn.includes(p))
).length;

// Phase-goal steering context
const phaseGoal = phaseCtx?.phase_goal || null;
const completedInPhase = phaseCtx?.completed_in_current_phase ?? 0;
const targetInPhase = phaseCtx?.target_sessions_in_current_phase ?? 3;
const sessionsRemaining = phaseCtx?.sessions_remaining_in_phase ?? Math.max(0, targetInPhase - completedInPhase);
const phaseStage = phaseCtx?.session_stage || serverSessionStage;

// Build task follow-up context string
const tasksForPrompt = activeTasksCtx.length > 0 ? activeTasksCtx : activeTasks;
const taskFollowUpStr = tasksForPrompt.length > 0
  ? tasksForPrompt.slice(0, 5).map((t) =>
      "- " + (t.dynamic_title || t.task_name || "Task") + ": " + (t.dynamic_description || t.task_description || "")
    ).join("\n")
  : "None assigned.";

// Build recent case notes context string
const caseNotesStr = caseNotesCtx.length > 0
  ? caseNotesCtx.slice(0, 3).map((cn) => {
      const notes = cn.case_notes;
      if (!notes || typeof notes !== "object") return null;
      const parts = [];
      if (notes.presenting_concern) parts.push("Concern: " + notes.presenting_concern);
      if (notes.dynamic_theme) parts.push("Theme: " + notes.dynamic_theme);
      if (notes.phase_progress) parts.push("Progress: " + notes.phase_progress);
      return parts.length > 0 ? parts.join("; ") : null;
    }).filter(Boolean).join("\n")
  : "No prior session notes.";

const sessionStage = messageCount < 6 ? "opening" : messageCount < 16 ? "middle" : "late";

const concernKeywords = ["anxiety", "stress", "burnout", "panic", "fear", "overwhelm", "stuck", "freeze"];
const concernAcknowledged = messages
  .filter((m) => m.role === "assistant")
  .slice(-4)
  .some((m) => {
    const text = String(m.content || "").toLowerCase();
    const hasValidation = text.includes("makes sense") || text.includes("understandable") || text.includes("thank you for sharing") || text.includes("you are carrying") || text.includes("that sounds");
    const hasConcernReference = concernKeywords.some((k) => text.includes(k));
    return hasValidation && hasConcernReference;
  });

const isExerciseMessage = (m) => {
  if (!m || m.role !== "assistant") return false;
  const dc = m.dynamic_content;
  const dcType = String(dc?.type || "").toLowerCase();
  const content = String(m.content || "").toLowerCase();
  return dcType === "exercise" || dcType === "exercise_card" || content.includes("exercise");
};

const exerciseMessageIndexes = messages
  .map((m, idx) => (isExerciseMessage(m) ? idx : -1))
  .filter((idx) => idx >= 0);

const hasAnyExerciseAlready = exerciseMessageIndexes.length > 0;
const firstExerciseIndex = hasAnyExerciseAlready ? exerciseMessageIndexes[0] : -1;
const firstExerciseAtOrBefore8 = hasAnyExerciseAlready && firstExerciseIndex <= 8;
const lastExerciseIndex = hasAnyExerciseAlready ? exerciseMessageIndexes[exerciseMessageIndexes.length - 1] : -1;
const turnsSinceLastExercise = hasAnyExerciseAlready ? (messages.length - lastExerciseIndex) : 999;
const exerciseCooldownPassed = turnsSinceLastExercise >= 6;
const exerciseCapReached = exerciseMessageIndexes.length >= 3;

const userAskedExercise = /\b(exercise|breathing|grounding|tool|technique|calm me|panic help)\b/i.test(latestUserMessage);
const freezeStuckSignal = /\b(stuck|freeze|frozen|can't move|unable to start|paralyzed)\b/i.test(latestUserMessage);

const shouldOfferExerciseNow =
  !isGreeting &&
  messageCount >= 6 &&
  messageCount <= 8 &&
  concernAcknowledged &&
  !hasAnyExerciseAlready;

const shouldOfferAdaptiveExercise =
  !isGreeting &&
  !exerciseCapReached &&
  !shouldOfferExerciseNow &&
  exerciseCooldownPassed &&
  (userAskedExercise || elevatedDistressDetected || freezeStuckSignal || repeatedConcern);

let shouldRunDiscovery = false;
let pacingInstruction = "";
if (isGreeting) {
  const greetingAnchors = [];
  if (sessionNumber > 1) {
    greetingAnchors.push(
      "- Reference at least one specific topic, insight, or moment from a prior session (use the cross-session transcript)."
    );
  }
  if (tasksForPrompt.length > 0) {
    greetingAnchors.push(
      "- Mention one active task and gently ask how it went or if user had a chance to try it."
    );
  }
  if (phaseGoal) {
    greetingAnchors.push(
      "- Briefly connect the session to the current phase goal: \"" + phaseGoal + "\""
    );
  }

  pacingInstruction = [
    "",
    "[GREETING]",
    "Greet " + (pd.name || "there") + " warmly. This is session " + sessionNumber + ".",
    sessionNumber > 1
      ? "IMPORTANT: Do NOT use a generic greeting. The user expects you to remember prior sessions."
      : "This is the first session — introduce yourself and reference their concerns.",
    ...greetingAnchors,
    "Set is_session_close to false."
  ].join("\n");
} else if (messageCount >= 20 && messageCount % 5 === 0) {
  pacingInstruction =
    "\n[SYSTEM] Turn " + messageCount + ". Recommend a clinical pathway. Set is_session_close to false.";
  shouldRunDiscovery = true;
}

// Continuity rules (apply to EVERY turn, not just greeting)
const continuityRules = [
  "### SESSION CONTINUITY RULES",
  "These rules apply to EVERY response, not just the greeting.",
  "- You have cross-session conversation history. Use it to avoid asking questions the user already answered.",
  "- When referencing prior context, be specific (name the situation, feeling, or detail — not just \"last time\").",
  "- If the user has active tasks, weave task follow-up naturally into conversation when relevant.",
  "- Do NOT repeat intake-style questions (name, age, concerns) if this information is already in the profile or transcript.",
  "- If user brings up a new topic, acknowledge the shift and connect it to their known context when possible.",
].join("\n");

// Phase-goal steering block
const phaseSteeringBlock = phaseGoal ? [
  "### PHASE-GOAL STEERING",
  "Current phase goal: \"" + phaseGoal + "\"",
  "Sessions completed in this phase: " + completedInPhase + " of " + targetInPhase + " (" + sessionsRemaining + " remaining).",
  "Phase stage: " + phaseStage,
  phaseStage === "early"
    ? "- Early phase: establish the focus area for this phase goal. Explore context and build working alliance around the goal."
    : phaseStage === "middle"
      ? "- Mid phase: actively work toward the phase goal. Use reframes, exercises, or structured interventions aligned with the goal."
      : "- Late phase: consolidate progress toward the phase goal. Verify readiness, name concrete gains, and prepare for transition.",
  "- Every response should subtly advance toward the phase goal. Do not drift into unrelated exploration unless the user initiates it.",
  "- If user raises an unrelated concern, validate it briefly, then gently bridge back to the phase goal.",
].join("\n") : "";

const progressionRules = [
  "### CONVERSATIONAL CADENCE (ASH + ABBY STYLE)",
  "- Keep response concise but allow multi-line markdown when it improves clarity.",
  "- Use exactly one brief validating statement, then one targeted follow-up question.",
  "- Advance the conversation each turn: avoid repeating prior phrasing or generic empathy loops.",
  "- Ground at least one sentence in a concrete user detail (role, context, event, timeline, relationship).",
  "- Offer one small next step only when readiness is visible; otherwise prioritize exploration.",
  "",
  "### ANTI-REPETITION RULES",
  "- Do not reuse stock openers from your previous 2 turns unless clinically necessary.",
  "- If user repeats a concern, switch strategy: summarize pattern + ask a sharper question.",
  "- If therapist wording has become repetitive, vary sentence openings and question form.",
  "",
  "### SESSION PROGRESSION TARGET",
  sessionStage === "opening"
    ? "- Opening stage: establish safety, context, and one clear immediate focus area."
    : sessionStage === "middle"
      ? "- Middle stage: identify maintaining cycle (thoughts-emotions-behaviors) and test one reframe."
      : "- Late stage: consolidate insight, name one practical action, and verify commitment/readiness.",
].join("\n");

const distressModeBlock = [
  "### ELEVATED DISTRESS (NON-CRISIS) PROTOCOL",
  "- Apply this only when user sounds emotionally overwhelmed but no explicit self-harm intent is present.",
  "- Sequence: (1) validate pain briefly, (2) normalize stress response, (3) ask one anchoring question.",
  "- Offer a tiny stabilizing action (breath, grounding, reaching one trusted person) without sounding directive.",
  "- Keep tone warm and steady; avoid over-intellectualizing or long lectures.",
  explicitCrisisCue
    ? "- Crisis cues detected in text; rely on crisis branch output if triggered."
    : "- No explicit crisis cues detected in latest message.",
].join("\n");

const structuredPlanBlock = [
  "### STRUCTURED PLAN MODE",
  "- If user asks for a plan, format reply using markdown with this pattern:",
  "  1) One-line rationale tied to user context.",
  "  2) A markdown heading + 3-5 numbered steps with simple, realistic actions.",
  "  3) A markdown bullet list for one fallback option on low-energy days.",
  "  4) End with one commitment-check question.",
  "- Keep the plan collaborative and non-judgmental.",
].join("\n");

const modeHints = [
  "### CURRENT TURN SIGNALS",
  "- session_number: " + sessionNumber,
  "- phase_stage: " + phaseStage,
  "- sessions_remaining_in_phase: " + sessionsRemaining,
  "- repeated_concern: " + String(repeatedConcern),
  "- repeated_therapist_openers_recently: " + String(repeatedTherapistOpeners >= 2),
  "- asks_for_structured_plan: " + String(asksForStructuredPlan),
  "- elevated_distress_detected: " + String(elevatedDistressDetected),
  "- explicit_crisis_cue_detected: " + String(explicitCrisisCue),
  "- exercise_already_offered: " + String(hasAnyExerciseAlready),
  "- first_exercise_at_or_before_turn_8: " + String(firstExerciseAtOrBefore8),
  "- exercise_cooldown_passed: " + String(exerciseCooldownPassed),
  "- exercise_cap_reached: " + String(exerciseCapReached),
  "- should_offer_exercise_now: " + String(shouldOfferExerciseNow),
  "- should_offer_adaptive_exercise: " + String(shouldOfferAdaptiveExercise),
].join("\n");

const qualityMetaSpec = [
  "### QUALITY META (include in output)",
  "Include quality_meta object in your JSON output:",
  "{",
  '  "conversation_mode": "normal|distress_support|structured_plan",',
  '  "context_used": true|false,',
  '  "task_followup_used": true|false,',
  '  "phase_goal_touched": true|false,',
  '  "session_stage": "' + phaseStage + '",',
  '  "detected_user_intent": "string",',
  '  "response_strategy": "string",',
  '  "novelty_anchor": "string",',
  '  "follow_up_question_type": "open|focused|reflective|commitment|none",',
  '  "distress_level": "low|moderate|elevated|unknown"',
  "}",
].join("\n");

const systemPrompt = [
  coachPrompt,
  "",
  phasePrompt,
  "",
  "### MEMORY CONTEXT",
  "Use the consolidated clinical memory as context only; do not perform memory write operations in this chat workflow.",
  "[CLIENT PROFILE]",
  personalDetails,
  "",
  "[CONSOLIDATED CLINICAL MEMORY]",
  memoriesStr,
  "",
  "[CURRENT CLINICAL THEME]",
  theme,
  "",
  "[ACTIVE TASKS — follow up when relevant]",
  taskFollowUpStr,
  "",
  "[RECENT SESSION CASE NOTES]",
  caseNotesStr,
  "",
  "[DYNAMIC EXERCISE LIBRARY]",
  "- Breathing: box_breathing, 4_7_8_breathing, diaphragmatic_breathing",
  "- Grounding: 5_4_3_2_1_senses, body_scan, progressive_muscle_relaxation",
  "- Meditation: calm_mind, focus_anchor, sleep_wind_down, gratitude_reflection",
  "",
  "### EXERCISE TRIGGER",
  shouldOfferExerciseNow
    ? "MANDATORY THIS TURN (ONE-TIME): Turn 6-8 window reached and concern acknowledged. Offer exactly one guided regulation exercise now."
    : shouldOfferAdaptiveExercise
      ? "ADAPTIVE EXERCISE MODE: user asked for help/tool or distress/stuck signals are elevated. Offer one relevant exercise this turn."
      : "Do not force exercise every turn. Offer only when clinically relevant.",
  shouldOfferExerciseNow
    ? "One-time early intervention: validate concern in 1-2 lines, then provide a single concrete exercise and ask if user wants to try it now."
    : shouldOfferAdaptiveExercise
      ? "Adaptive intervention: use one exercise only if it advances regulation; otherwise continue focused exploration."
      : "Maintain conversational flow without repetitive exercise suggestions.",
  "Guardrails: never offer more than 3 exercises/session; keep at least ~6 messages cooldown between exercise offers.",
  'Set dynamic_in_chat_exercise to a valid EXERCISE_ID when shouldOfferExerciseNow OR shouldOfferAdaptiveExercise is true; else set JSON null.',
  'If you include dynamic_content, use type "exercise" or "exercise_card" and payload = same id.',
  "",
  "[CROSS-SESSION TRANSCRIPT (last 20 turns)]",
  transcript,
  "",
  continuityRules,
  "",
  phaseSteeringBlock,
  "",
  modeHints,
  "",
  progressionRules,
  "",
  distressModeBlock,
  "",
  structuredPlanBlock,
  "",
  pacingInstruction,
  "",
  "### STRICT STRUCTURED OUTPUT (READ CAREFULLY)",
  "After any tool calls, your FINAL assistant message must be valid JSON ONLY (no markdown fences, no prose outside JSON).",
  "Either:",
  "  A) Top-level keys: reply (string markdown allowed, may include multi-line content), is_session_close (boolean), dynamic_in_chat_exercise (string or null). Optional dynamic_content and quality_meta.",
  '  OR B) One top-level key "output" whose value is that same object.',
  'dynamic_content.type must be exactly "exercise" or "exercise_card".',
  "Use JSON null for dynamic_in_chat_exercise when no exercise (not the string \"null\").",
  "reply may include markdown (lists, headings, emphasis, line breaks), but do not wrap reply in triple backticks.",
  qualityMetaSpec,
  "",
  "### OPERATIONAL PROTOCOL",
  "Emit ONLY the final JSON as specified above.",
].join("\n");

return [
  {
    json: {
      systemPrompt,
      userMessage: latestUserMessage,
      profileId,
      sessionId,
      shouldRunDiscovery,
      messageCount,
      promptSignals: {
        asksForStructuredPlan,
        elevatedDistressDetected,
        repeatedConcern,
        repeatedTherapistOpeners: repeatedTherapistOpeners >= 2,
        phaseStage,
        sessionNumber,
        contextAvailable: last20.length > 0,
        tasksAvailable: tasksForPrompt.length > 0,
        concernAcknowledged,
        shouldOfferExerciseNow,
        shouldOfferAdaptiveExercise,
        exerciseCooldownPassed,
        exerciseCapReached,
        hasAnyExerciseAlready,
      },
    },
  },
];

