parameters.jsCode:
/**
 * FORMAT FINAL RESPONSE (v8)
 * Unwraps therapist parser output, normalizes exercise types,
 * passes through quality_meta with continuity/phase signals.
 */

const webhookNode = $("Webhook").first();
const therapistNode = $("Therapist Agent").first();
if (!therapistNode) throw new Error("Therapist Agent output not found.");

const data = webhookNode.json.body || webhookNode.json || {};
const rawOutput = therapistNode.json.output;
const promptBuilderNode = $("Prompt Builder").first();
const promptSignals = promptBuilderNode?.json?.promptSignals || {};

function unwrapTherapist(o) {
  if (o == null || typeof o !== "object") return {};
  if (typeof o.reply === "string" || typeof o.is_session_close === "boolean") return o;
  if (o.output && typeof o.output === "object") {
    const inner = o.output;
    if (typeof inner.reply === "string" || typeof inner.is_session_close === "boolean") return inner;
  }
  return o;
}

let therapistOutput = unwrapTherapist(rawOutput);
if (typeof rawOutput === "string") {
  therapistOutput = { reply: rawOutput };
}

const reply =
  therapistOutput.reply || (typeof rawOutput === "string" ? rawOutput : "");

let dynamicContent = therapistOutput.dynamic_content || null;
if (dynamicContent && dynamicContent.type === "exercise_card") {
  dynamicContent = { ...dynamicContent, type: "exercise" };
}

const slug =
  therapistOutput.dynamic_in_chat_exercise ?? dynamicContent?.payload ?? null;

const crisisOutput = $("Crisis Screening Agent").first()?.json?.output || {};

const finalResponse = {
  reply,
  session_state: data.session_state || "active",
  pathway: data.pathway || "engagement_rapport_and_assessment",
  is_session_close: therapistOutput.is_session_close === true,
  dynamic_in_chat_exercise: slug,
  guardrail_status: "passed",
  crisis_detected: Boolean(crisisOutput.crisis_detected),
  crisis_type: crisisOutput.crisis_type || null,
};

if (dynamicContent) {
  finalResponse.dynamic_content = dynamicContent;
}

// Pass through quality_meta from therapist output, enriched with prompt-level signals
const rawQualityMeta = therapistOutput.quality_meta && typeof therapistOutput.quality_meta === "object"
  ? therapistOutput.quality_meta
  : {};

finalResponse.quality_meta = {
  ...rawQualityMeta,
  context_used: rawQualityMeta.context_used ?? promptSignals.contextAvailable ?? false,
  task_followup_used: rawQualityMeta.task_followup_used ?? false,
  phase_goal_touched: rawQualityMeta.phase_goal_touched ?? false,
  session_stage: rawQualityMeta.session_stage || promptSignals.phaseStage || "early",
  session_number: promptSignals.sessionNumber || data.session_number || 1,
};

try {
  const discoveryNode = $("Discovery Agent").first();
